import type { NextFunction, Request, Response } from "express";
import { technicianService } from "./technician.service";
import type { ITechnicianFilters } from "./technician.interface";
import type { BookingStatus } from "../../../generated/prisma/client";
import AppError from "../../../utils/AppError";
import { sendResponse } from "../../../utils/response";

const getTechnicians = async (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  try {
    const filters = req.query as ITechnicianFilters;
    const result = await technicianService.getTechniciansFormDb(filters);

    sendResponse(res, {
      statusCode: 200,
      message: "technicians fetched successfully",
      data: result,
    });
  } catch (error) {
    next(error);
  }
};

const getTechnicianById = async (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  try {
    const { id } = req.params;
    const result = await technicianService.getTechnicianByIdFromDb(
      id as string,
    );

    sendResponse(res, {
      statusCode: 200,
      message: "technician fetched successfully",
      data: result,
    });
  } catch (error) {
    next(error);
  }
};

const updateProfile = async (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  try {
    const userId = (req as Request & { user?: { id: string } }).user!.id;
    const result = await technicianService.updateTechnicianProfileDb(
      userId,
      req.body,
    );

    sendResponse(res, {
      statusCode: 200,
      message: "technician profile updated successfully",
      data: result,
    });
  } catch (error) {
    next(error);
  }
};

